class Solution:
    def getMaxRepetitions(self, s1, n1, s2, n2):
        j = 0
        s2_count = 0
        for _ in range(n1):
            for ch in s1:
                if ch == s2[j]:
                    j += 1
                    if j == len(s2):
                        j = 0
                        s2_count += 1
        return s2_count // n2

