class Solution:
    def getMaxRepetitions(self, s1, n1, s2, n2):
        if n1 == 0:
            return 0
        index_after = [0] * len(s2)
        counts_per_start = [0] * len(s2)
        for start in range(len(s2)):
            j = start
            cnt = 0
            for ch in s1:
                if ch == s2[j]:
                    j += 1
                    if j == len(s2):
                        j = 0
                        cnt += 1
            counts_per_start[start] = cnt
            index_after[start] = j
        total = 0
        cur = 0
        seen = {}
        block = 0
        while block < n1:
            if cur in seen:
                prev_block, prev_total = seen[cur]
                cycle_blocks = block - prev_block
                cycle_count = total - prev_total
                remaining = n1 - block
                cycles = remaining // cycle_blocks
                total += cycles * cycle_count
                block += cycles * cycle_blocks
                seen = {}
                if block >= n1:
                    break
            else:
                seen[cur] = (block, total)
            total += counts_per_start[cur]
            cur = index_after[cur]
            block += 1
        return total // n2

