var getMaxRepetitions = function(s1, n1, s2, n2) {
    if (n1 === 0) return 0;
    const L = s2.length;
    const indexAfter = new Array(L).fill(0);
    const countsPerStart = new Array(L).fill(0);
    for (let start = 0; start < L; start++) {
        let j = start, cnt = 0;
        for (const ch of s1) {
            if (ch === s2[j]) {
                j++;
                if (j === L) { j = 0; cnt++; }
            }
        }
        countsPerStart[start] = cnt;
        indexAfter[start] = j;
    }
    let total = 0, cur = 0, block = 0;
    let seen = new Map();
    while (block < n1) {
        if (seen.has(cur)) {
            const [prevBlock, prevTotal] = seen.get(cur);
            const cycleBlocks = block - prevBlock;
            const cycleCount = total - prevTotal;
            const remaining = n1 - block;
            const cycles = Math.floor(remaining / cycleBlocks);
            total += cycles * cycleCount;
            block += cycles * cycleBlocks;
            seen = new Map();
            if (block >= n1) break;
        } else {
            seen.set(cur, [block, total]);
        }
        total += countsPerStart[cur];
        cur = indexAfter[cur];
        block++;
    }
    return Math.floor(total / n2);
};
